public class ScheduledTaskEditRequest { public string Agent { get; set; } = string.Empty; public string TaskId { get; set; } = string.Empty; public string? Title { get; set; } public string? Content { get; set; } public string? TimeZone { get; set; } public string? Status { get; set; } public ScheduledTaskSchedule? Schedule { get; set; } public List<ScheduledTaskTarget>? Targets { get; set; } }
