public static class ScheduledTaskStatuses { public const string Enabled = "enabled"; public const string Paused = "paused"; public const string Completed = "completed"; public const string Deleted = "deleted"; public const string Quarantined = "quarantined"; public const string Replaced = "replaced"; }
public static class ScheduledTaskRunStates { public const string Idle = "idle"; public const string Running = "running"; }
public static class ScheduledTaskRunStatuses { public const string Running = "running"; public const string Succeeded = "succeeded"; public const string Failed = "failed"; public const string Canceled = "canceled"; public const string Interrupted = "interrupted"; public const string Stalled = "stalled"; }
